function showUsers(arr) {
  document.querySelector(".cards").innerHTML = "";

  arr.forEach((user) => {
    const card = document.createElement("div");
    card.classList.add("card");

    const img = document.createElement("img");
    img.src = user.pic;
    img.classList.add("bg-img");

    const content = document.createElement("div");
    content.classList.add("content");

    const h3 = document.createElement("h3");
    h3.textContent = user.name;

    const p = document.createElement("p");
    p.textContent = user.bio;

    content.appendChild(h3);
    content.appendChild(p);

    card.appendChild(img);
    card.appendChild(content);

    document.querySelector(".cards").appendChild(card);
  });
}


showUsers(users);


let inp = document.querySelector(".inp");

inp.addEventListener("input", function () {
  let value = inp.value.toLowerCase();

  let filteredUsers = users.filter((user) =>
    user.name.toLowerCase().includes(value)
  );

  showUsers(filteredUsers);
});
  const container = document.querySelector(".imgg");
  const text = document.querySelector(".t");

  let targetX = 0;
  let targetY = 0;
  let currentX = 0;
  let currentY = 0;

  const intensity = 140; 
  const ease = 0.05;   

  function lerp(a, b, n) {
    return a + (b - a) * n;
  }

  container.addEventListener("mousemove", function (e) {
    const rect = container.getBoundingClientRect();

    targetX = ((e.clientX - rect.left) / rect.width - 0.5) * intensity;
    targetY = ((e.clientY - rect.top) / rect.height - 0.5) * intensity;
  });

  container.addEventListener("mouseleave", function () {
    targetX = 0;
    targetY = 0;
  });

  function animate() {
    currentX = lerp(currentX, targetX, ease);
    currentY = lerp(currentY, targetY, ease);

    text.style.transform =
      "translate(" + currentX + "px, " + currentY + "px) " +
      "rotateX(" + (-currentY / 6) + "deg) " +
      "rotateY(" + (currentX / 6) + "deg)";

    requestAnimationFrame(animate);
  }

  animate();
    const preloader = document.getElementById('preloader');
  const mainContent = document.getElementById('main-content');
  const video = document.getElementById('introVideo');


  video.addEventListener('ended', () => {

    preloader.style.opacity = '0';

    
    setTimeout(() => {
      preloader.style.display = 'none';
  
      mainContent.classList.add('visible');
      
      document.body.style.overflow = 'auto';
    }, 1000); 
  });

  
  preloader.addEventListener('click', () => {
    video.pause();
    video.currentTime = video.duration; 
  });